import java.util.Scanner;
import java.util.Arrays;

public class SecureBuffer {

    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);

        System.out.print("Enter your name: ");
        String name = scanner.nextLine().trim(); // Read a line of input and trim any leading/trailing whitespaces

        // Ensure that the input does not exceed the buffer size
        byte[] buffer = new byte[10];
        int length = Math.min(name.length(), buffer.length);

        // Copy only up to the allowed length into the buffer
        System.arraycopy(name.getBytes(), 0, buffer, 0, length);

        // Fill any remaining bytes with zeros to prevent leaking sensitive data
        Arrays.fill(buffer, length, buffer.length, (byte) 0);

        System.out.println("Hello, " + new String(buffer));
    }
}

### Explanation:
취약유형: Buffer Overflow
